$ErrorActionPreference='Stop'; $Root=Resolve-Path (Join-Path $PSScriptRoot '..'); dotnet --info | Out-Null; psql --version | Out-Null; if(-not $env:DATABASE_URL){$env:DATABASE_URL='postgresql://integrarp@localhost:5432/integrarp'}; psql -X $env:DATABASE_URL --set ON_ERROR_STOP=1 --file (Join-Path $Root 'database/script_completop.sql'); psql -X $env:DATABASE_URL --set ON_ERROR_STOP=1 --file (Join-Path $Root 'database/validate_script_completop.sql'); dotnet restore (Join-Path $Root 'IntegraRP.sln'); dotnet build (Join-Path $Root 'IntegraRP.sln') --no-restore; New-Item -Force -ItemType Directory (Join-Path $Root 'storage'),(Join-Path $Root 'logs') | Out-Null
